Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

#include <iostream>
#include <fstream>
#include <string>
#include <algorithm>

using namespace std;

int main() {
    string filename, word;
    cout << "Enter filename: ";
    cin >> filename;
    cout << "Enter word to search for: ";
    cin >> word;
    ifstream file(filename.c_str());
    if (!file) {
        cerr << "Error opening file." << endl;
        return 1;
    }
    int count = 0;
    string line;
    while (getline(file, line)) {
        // Convert line to lowercase
        transform(line.begin(), line.end(), line.begin(), ::tolower);
        // Remove punctuation from line
        line.erase(remove_if(line.begin(), line.end(), ::ispunct), line.end());
        // Check if line contains the word
        if (line.find(word)!= string::npos) {
            count++;
        }
    }
    file.close();
    cout << "The word \"" << word << "\" occurs " << count << " times in the file." << endl;
    return 0;
}

